import {
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Note } from './note.entity';
import { CreateNoteDto } from './create-note.dto';
import { CacheService } from '../infra/cache.service';
import { BrokerService } from '../infra/broker.service';
import { SearchService } from '../infra/search.service';

const CACHE_TTL_SEC = 30;
const cacheKey = (id: string) => `note:${id}`;

@Injectable()
export class NotesService {
  private readonly logger = new Logger(NotesService.name);

  constructor(
    @InjectRepository(Note) private readonly repo: Repository<Note>,
    private readonly cache: CacheService,
    private readonly broker: BrokerService,
    private readonly search: SearchService,
  ) {}

  async create(dto: CreateNoteDto): Promise<Note> {
    const note = this.repo.create(dto);
    const saved = await this.repo.save(note);

    // Fan out: publish and index. Failures should not abort the response.
    this.broker
      .publish('notes.created', saved)
      .catch((e) => this.logger.warn(`broker publish failed: ${e.message}`));
    this.search
      .index(saved)
      .catch((e) => this.logger.warn(`search index failed: ${e.message}`));

    return saved;
  }

  async list(): Promise<Note[]> {
    return this.repo.find({ order: { createdAt: 'DESC' } });
  }

  async findOne(id: string): Promise<Note> {
    const cached = await this.cache.getJson<Note>(cacheKey(id));
    if (cached) return cached;

    const note = await this.repo.findOne({ where: { id } });
    if (!note) throw new NotFoundException(`note ${id} not found`);

    await this.cache
      .setJson(cacheKey(id), note, CACHE_TTL_SEC)
      .catch((e) => this.logger.warn(`cache set failed: ${e.message}`));
    return note;
  }

  async remove(id: string): Promise<void> {
    const note = await this.repo.findOne({ where: { id } });
    if (!note) throw new NotFoundException(`note ${id} not found`);

    await this.repo.delete(id);
    await this.cache
      .del(cacheKey(id))
      .catch((e) => this.logger.warn(`cache del failed: ${e.message}`));

    this.broker
      .publish('notes.deleted', { id })
      .catch((e) => this.logger.warn(`broker publish failed: ${e.message}`));
    this.search
      .remove(id)
      .catch((e) => this.logger.warn(`search remove failed: ${e.message}`));
  }

  async search_(q: string) {
    return this.search.search(q);
  }

  async search(q: string) {
    return this.search.search(q);
  }
}

