import {
  Injectable,
  Logger,
  OnModuleDestroy,
  OnModuleInit,
} from '@nestjs/common';
import Redis from 'ioredis';

@Injectable()
export class CacheService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(CacheService.name);
  private client!: Redis;

  async onModuleInit() {
    const host = process.env.cache_hostname || '127.0.0.1';
    const port = parseInt(process.env.cache_port || '6379', 10);
    this.client = new Redis({
      host,
      port,
      lazyConnect: false,
      maxRetriesPerRequest: 2,
    });
    this.client.on('error', (e) => this.logger.warn(`redis: ${e.message}`));
  }

  async onModuleDestroy() {
    try {
      await this.client?.quit();
    } catch {
      /* ignore */
    }
  }

  async getJson<T>(key: string): Promise<T | null> {
    const raw = await this.client.get(key);
    if (!raw) return null;
    try {
      return JSON.parse(raw) as T;
    } catch {
      return null;
    }
  }

  async setJson(key: string, value: unknown, ttlSec: number): Promise<void> {
    await this.client.set(key, JSON.stringify(value), 'EX', ttlSec);
  }

  async del(key: string): Promise<void> {
    await this.client.del(key);
  }
}

import {
  Injectable,
  Logger,
  OnModuleDestroy,
  OnModuleInit,
} from '@nestjs/common';
import { connect, NatsConnection, JSONCodec, Codec } from 'nats';

@Injectable()
export class BrokerService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(BrokerService.name);
  private nc: NatsConnection | null = null;
  private codec: Codec<unknown> = JSONCodec();

  async onModuleInit() {
    // nats-v2 client rejects credentials embedded in the servers URL
    // ("Invalid URL"). Pass host:port as servers, user/pass as options.
    const host = process.env.broker_hostname || 'broker';
    const port = process.env.broker_port || '4222';
    const servers = `nats://${host}:${port}`;
    try {
      this.nc = await connect({
        servers,
        user: process.env.broker_user,
        pass: process.env.broker_password,
        name: 'api',
        timeout: 3000,
      });
      this.logger.log(`nats connected: ${this.nc.getServer()}`);
      (async () => {
        for await (const status of this.nc!.status()) {
          this.logger.debug(`nats status: ${status.type}`);
        }
      })().catch(() => {});
    } catch (e: any) {
      this.logger.warn(`nats connect failed: ${e.message}`);
      this.nc = null;
    }
  }

  async onModuleDestroy() {
    try {
      await this.nc?.drain();
    } catch {
      /* ignore */
    }
  }

  async publish(subject: string, payload: unknown): Promise<void> {
    if (!this.nc) {
      this.logger.warn(`nats not connected; dropping ${subject}`);
      return;
    }
    this.nc.publish(subject, this.codec.encode(payload));
  }
}

import {
  Injectable,
  Logger,
  OnModuleInit,
} from '@nestjs/common';
import { Meilisearch } from 'meilisearch';
import { Note } from '../notes/note.entity';

const INDEX = 'notes';

@Injectable()
export class SearchService implements OnModuleInit {
  private readonly logger = new Logger(SearchService.name);
  private client!: Meilisearch;

  async onModuleInit() {
    const host =
      process.env.MEILI_URL ||
      `http://${process.env.search_hostname}:${process.env.search_port || 7700}`;
    const apiKey =
      process.env.MEILI_KEY || process.env.search_masterKey || '';
    this.client = new Meilisearch({ host, apiKey });

    try {
      await this.client.getIndex(INDEX);
    } catch {
      try {
        await this.client.createIndex(INDEX, { primaryKey: 'id' });
        this.logger.log(`created meili index ${INDEX}`);
      } catch (e: any) {
        this.logger.warn(`meili createIndex failed: ${e.message}`);
      }
    }
  }

  async index(note: Note): Promise<void> {
    await this.client.index(INDEX).addDocuments([
      {
        id: note.id,
        title: note.title,
        body: note.body,
        createdAt: note.createdAt,
      },
    ]);
  }

  async remove(id: string): Promise<void> {
    await this.client.index(INDEX).deleteDocument(id);
  }

  async search(q: string) {
    const res = await this.client.index(INDEX).search(q);
    return { query: q, hits: res.hits };
  }
}

import { Injectable, OnModuleInit } from '@nestjs/common';
import {
  S3Client,
  PutObjectCommand,
  GetObjectCommand,
} from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

@Injectable()
export class StorageService implements OnModuleInit {
  private client!: S3Client;
  private bucket!: string;

  onModuleInit() {
    const endpoint =
      process.env.S3_ENDPOINT ||
      `http://${process.env.storage_apiHost}`;
    this.bucket =
      process.env.S3_BUCKET || process.env.storage_bucketName || '';
    this.client = new S3Client({
      endpoint,
      region: 'us-east-1',
      forcePathStyle: true,
      credentials: {
        accessKeyId:
          process.env.S3_ACCESS_KEY ||
          process.env.storage_accessKeyId ||
          '',
        secretAccessKey:
          process.env.S3_SECRET_KEY ||
          process.env.storage_secretAccessKey ||
          '',
      },
    });
  }

  async putObject(
    key: string,
    body: Buffer,
    contentType?: string,
  ): Promise<void> {
    await this.client.send(
      new PutObjectCommand({
        Bucket: this.bucket,
        Key: key,
        Body: body,
        ContentType: contentType,
      }),
    );
  }

  async getSignedUrl(key: string, expiresInSec = 300): Promise<string> {
    const cmd = new GetObjectCommand({ Bucket: this.bucket, Key: key });
    return getSignedUrl(this.client, cmd, { expiresIn: expiresInSec });
  }
}

import { Module } from '@nestjs/common';
import { UploadsController } from './uploads.controller';

@Module({
  controllers: [UploadsController],
})
export class UploadsModule {}

import {
  BadRequestException,
  Controller,
  Post,
  UploadedFile,
  UseInterceptors,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { randomUUID } from 'crypto';
import { StorageService } from '../infra/storage.service';

type MulterFile = {
  fieldname: string;
  originalname: string;
  mimetype: string;
  size: number;
  buffer: Buffer;
};

@Controller('uploads')
export class UploadsController {
  constructor(private readonly storage: StorageService) {}

  @Post()
  @UseInterceptors(FileInterceptor('file'))
  async upload(@UploadedFile() file?: MulterFile) {
    if (!file) {
      throw new BadRequestException('multipart field "file" is required');
    }
    const safeName = (file.originalname || 'upload').replace(
      /[^a-zA-Z0-9._-]/g,
      '_',
    );
    const key = `uploads/${Date.now()}-${randomUUID()}-${safeName}`;
    await this.storage.putObject(key, file.buffer, file.mimetype);
    const url = await this.storage.getSignedUrl(key, 300);
    return {
      key,
      url,
      size: file.size,
      contentType: file.mimetype,
    };
  }
}

